// Filter unprocessed rows and batch them for AI analysis
var items = $input.all();
var unprocessed = [];
for (var i = 0; i < items.length; i++) {
  var row = items[i].json;
  if (!row.Processed || row.Processed === '' || row.Processed === 'no') {
    unprocessed.push({
      rowIndex: i + 2,
      timestamp: row.Timestamp || '',
      response: row.Feedback || row.Response || row['Your feedback'] || '',
      rating: row.Rating || row.Score || ''
    });
  }
}
if (unprocessed.length === 0) {
  return { json: { skip: true, message: 'No new responses to analyze' } };
}
var feedbackText = unprocessed.map(function(r, idx) {
  return 'Response ' + (idx + 1) + ' (row ' + r.rowIndex + '): ' + r.response + (r.rating ? ' [Rating: ' + r.rating + ']' : '');
}).join('\n');
return { json: { skip: false, count: unprocessed.length, feedbackText: feedbackText, rows: unprocessed } };

// Parse AI response and prepare data for Sheets and email
var aiResponse = $input.first().json;
var text = aiResponse.text || aiResponse.response || JSON.stringify(aiResponse);
var parsed;
try {
  var jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch(e) {
  parsed = { responses: [], summary: { total: 0, positive: 0, neutral: 0, negative: 0, topThemes: [], recommendation: 'Could not parse AI response' } };
}
var responses = parsed.responses || [];
var summary = parsed.summary || {};
var rows = [];
for (var i = 0; i < responses.length; i++) {
  var r = responses[i];
  rows.push({
    rowIndex: r.rowIndex || 0,
    sentiment: r.sentiment || 'unknown',
    score: r.score || 5,
    category: r.category || 'other',
    theme: r.theme || ''
  });
}
var positiveRate = summary.total > 0 ? Math.round((summary.positive / summary.total) * 100) : 0;
var negativeRate = summary.total > 0 ? Math.round((summary.negative / summary.total) * 100) : 0;
var emailBody = '<h2>Customer Feedback Analysis Report</h2>';
emailBody += '<p><strong>Date:</strong> ' + new Date().toISOString().split('T')[0] + '</p>';
emailBody += '<p><strong>Responses analyzed:</strong> ' + (summary.total || 0) + '</p>';
emailBody += '<h3>Sentiment Distribution</h3>';
emailBody += '<ul>';
emailBody += '<li>Positive: ' + (summary.positive || 0) + ' (' + positiveRate + '%)</li>';
emailBody += '<li>Neutral: ' + (summary.neutral || 0) + '</li>';
emailBody += '<li>Negative: ' + (summary.negative || 0) + ' (' + negativeRate + '%)</li>';
emailBody += '</ul>';
emailBody += '<h3>Top Themes</h3><ul>';
var themes = summary.topThemes || [];
for (var t = 0; t < themes.length; t++) {
  emailBody += '<li>' + themes[t] + '</li>';
}
emailBody += '</ul>';
emailBody += '<h3>Recommendation</h3><p>' + (summary.recommendation || 'N/A') + '</p>';
return { json: { rows: rows, summary: summary, positiveRate: positiveRate, negativeRate: negativeRate, emailBody: emailBody, topThemes: (themes).join(', '), recommendation: summary.recommendation || 'N/A', total: summary.total || 0 } };
